parameters.jsCode:
// Split meetings into individual items for the calendar node
const data = $input.first().json;
const meetings = data.chaos.meetings || [];

return meetings.map((meeting, i) => {
  // Schedule meetings on consecutive days starting tomorrow
  const startDate = new Date();
  startDate.setDate(startDate.getDate() + i + 1);
  startDate.setHours(9 + i, 0, 0, 0);  // 9am, 10am, 11am

  const endDate = new Date(startDate);
  endDate.setMinutes(endDate.getMinutes() + meeting.duration_minutes);

  return {
    json: {
      title: meeting.title,
      description: meeting.description + '\n\nURGENCY: ' + meeting.urgency + '\n\nOriginal trigger: ' + data.original_subject,
      duration: meeting.duration_minutes,
      start: startDate.toISOString(),
      end: endDate.toISOString(),
      attendee: data.original_sender
    }
  };
});

// Split stakeholder emails into individual items
const data = $input.first().json;
const emails = data.chaos.stakeholder_emails || [];

// In a real demo these would go to demo/test addresses
return emails.map(email => ({
  json: {
    to_role: email.to_role,
    subject: email.subject,
    body: email.body + '\n\n---\nThis stakeholder notification was auto-generated regarding: ' + data.original_subject + '\n\n[This is a demo - Automation for Good...and Chaos]'
  }
}));

// Generate a beautiful summary of all the chaos created
const data = $('Parse Chaos Plan').first().json;
const chaos = data.chaos;

let summary = '🏛️ BUREAUCRACY MACHINE - FULL CHAOS REPORT\n';
summary += '═'.repeat(50) + '\n\n';

summary += '📨 ORIGINAL TRIGGER\n';
summary += `From: ${data.original_sender_name} <${data.original_sender}>\n`;
summary += `Subject: ${data.original_subject}\n`;
summary += `Body: ${data.original_body}\n\n`;

summary += '🔴 RISK ASSESSMENT: ' + chaos.risk_level + '\n';
summary += '📋 ' + chaos.analysis + '\n\n';

summary += '━'.repeat(50) + '\n';
summary += '📧 AUTO-GENERATED REPLY\n';
summary += '━'.repeat(50) + '\n';
summary += `Subject: ${chaos.reply_email.subject}\n\n`;
summary += chaos.reply_email.body + '\n\n';

summary += '━'.repeat(50) + '\n';
summary += '📅 MEETINGS SCHEDULED (' + chaos.meetings.length + ')\n';
summary += '━'.repeat(50) + '\n';
chaos.meetings.forEach((m, i) => {
  summary += `\n${i+1}. ${m.title} (${m.duration_minutes} min)\n`;
  summary += `   📋 ${m.description}\n`;
  summary += `   ⚠️ Urgency: ${m.urgency}\n`;
});

summary += '\n' + '━'.repeat(50) + '\n';
summary += '📨 STAKEHOLDER NOTIFICATIONS (' + chaos.stakeholder_emails.length + ')\n';
summary += '━'.repeat(50) + '\n';
chaos.stakeholder_emails.forEach((e, i) => {
  summary += `\n${i+1}. To: ${e.to_role}\n`;
  summary += `   Subject: ${e.subject}\n`;
  summary += `   ${e.body}\n`;
});

summary += '\n' + '━'.repeat(50) + '\n';
summary += '✅ ACTION ITEMS (' + chaos.action_items.length + ')\n';
summary += '━'.repeat(50) + '\n';
chaos.action_items.forEach((item, i) => {
  summary += `${i+1}. ${item}\n`;
});

summary += '\n' + '━'.repeat(50) + '\n';
summary += '🏛️ COMMITTEES FORMED (' + chaos.committees_to_form.length + ')\n';
summary += '━'.repeat(50) + '\n';
chaos.committees_to_form.forEach((c, i) => {
  summary += `\n${i+1}. ${c.name}\n`;
  summary += `   Purpose: ${c.purpose}\n`;
  summary += `   Cadence: ${c.meeting_cadence}\n`;
});

summary += '\n' + '═'.repeat(50) + '\n';
summary += '💥 ONE EMAIL → ' + (
  1 + chaos.meetings.length + chaos.stakeholder_emails.length + 
  chaos.action_items.length + chaos.committees_to_form.length
) + ' BUREAUCRATIC ARTIFACTS GENERATED 💥\n';
summary += '\n[Demo: Automation for Good...and Chaos]';

return [{ json: { summary } }];
